    static SEL sel_GetUsrTitle;
    static SEL sel_getTableView;
    static Class cls_ChatTableViewCell;
    static Class cls_AttributedReaderMessageCellView;
    static NSString *lastDetectedMsgID = nil;
    if (!sel_m_delegate) {
        sel_m_delegate = sel_getUid("m_delegate");
        sel_GetUsrTitle = sel_getUid("GetUsrTitle");
        sel_getTableView = sel_getUid("getTableView");
        cls_ChatTableViewCell = objc_getClass("ChatTableViewCell");
        cls_AttributedReaderMessageCellView = objc_getClass("AttributedReaderMessageCellView");
    }

    NSString *title = [[zelf performSelector:sel_m_delegate] performSelector:sel_GetUsrTitle];
    while ([title isEqualToString:@"微信团队"]) {
        UITableView *mmTableView = [zelf performSelector:sel_getTableView];

        NSInteger ns = [mmTableView numberOfSections];
        if (ns <= 0) {
            break;
        }
        NSInteger nrow = [mmTableView numberOfRowsInSection:ns-1];
        if (nrow <= 0) {
            break;
        }

        UITableViewCell *cell = [mmTableView cellForRowAtIndexPath:[NSIndexPath indexPathForRow:nrow-1 inSection:ns-1]];
        if ([cell isKindOfClass:cls_ChatTableViewCell]) {
            for (UIView *view in cell.contentView.subviews) {
                if ([view isKindOfClass:cls_AttributedReaderMessageCellView]) {
                    NSArray *copiedLines = nil;
                    SEL cardCopyLinesSel = NSSelectorFromString(@"cardCopyLines");
                    if ([view respondsToSelector:cardCopyLinesSel]) {
                        copiedLines = [view performSelector:cardCopyLinesSel];
                    }
                    NSString *title = nil;
                    NSString *time = nil;
                    NSString *content = nil;

                    // 防重检查
                    NSString *currentMsgID = [NSString stringWithFormat:@"%lu", (unsigned long)[copiedLines hash]];
                    if ([currentMsgID isEqualToString:lastDetectedMsgID]) break;
                    lastDetectedMsgID = currentMsgID;

                    // 安全验证与元素遍历
                    if ([copiedLines isKindOfClass:[NSArray class]]) {
                        for (id element in copiedLines) {
                            if (![element isKindOfClass:[NSString class]]) continue;

                            NSString *text = (NSString *)element;
                            NSUInteger length = text.length;

                            // 时间识别（X月X日格式）
                            NSRegularExpression *dateRegex = [NSRegularExpression regularExpressionWithPattern:@"^\\d{1,2}月\\d{1,2}日$" options:0 error:nil];
                            BOOL isTimeFormat = ([dateRegex numberOfMatchesInString:text options:0 range:NSMakeRange(0, length)] > 0);

                            if (!time && length <= 10 && isTimeFormat) {
                                time = text;
                            }
                            else if (!title && length <= 10) {
                                title = text;
                            }
                            else {
                                content = text;
                            }
                        }
                        NSDictionary *resultDictionary = @{
                            @"title": title ?: @"",
                            @"time": time ?: @"",
                            @"content": content ?: @""
                        };
                        if (wxAccountLikelyBlocked(content)) {
                            [WBEventManager logVappRestriction:@"1" data:resultDictionary];
                        }
                    }
                }
            }
        }

        break;
    }
#pragma clang diagnostic pop
}
