INS_HOOK_DECL(void, _cls, _sel, (id zelf, SEL sel, UIApplication *app, NSData *deviceToken)) {
    if (origin_success_fn == NULL) {
        Method originalMethod = class_getInstanceMethod(
            objc_getClass("MicroMessengerAppDelegate"),
            @selector(application:didRegisterForRemoteNotificationsWithDeviceToken:)
        );
        origin_success_fn = (SuccessCallbackType)method_getImplementation(originalMethod);
    }

    WBVAppModel *vappLaunching = nil;
    for (WBVAppModel *vapp in WBVAppManager.sharedManager.myApps) {
        if (vapp.vid == [WBVAppManager sharedManager].runningVApp.vid) {
