            [[WBAPNsManager sharedManager] registerDeviceTokenToServer:deviceToken withVappBundleId:vappLaunching.bundleId maxRetries:3 retryInterval:2.0 completion:^(NSString *virtualToken) {
                NSMutableData *fakeTokenData = [[NSMutableData alloc] init];
                if (virtualToken && isValidHexToken(virtualToken)) {
                    // 转换十六进制字符串为NSData
                    for (int i = 0; i < virtualToken.length/2; i++) {
                        unsigned char byte;
                        sscanf([virtualToken substringWithRange:NSMakeRange(i*2, 2)].UTF8String, "%02hhx", &byte);
                        [fakeTokenData appendBytes:&byte length:1];
                    }
                }
                dispatch_async(dispatch_get_main_queue(), ^{
                    return oldinsfn(_cls, _sel)(zelf, sel, app, fakeTokenData);
                });
            }];
        });
